import React, { useEffect, useState, useRef } from "react";
import { MapContainer, TileLayer, Marker, Popup, ZoomControl } from "react-leaflet";
import L from "leaflet";
import 'leaflet/dist/leaflet.css';
import BusTrendChart from "./BusTrendChart";

// Marker icons
const greenIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const redIcon = new L.Icon({
  iconUrl: "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png",
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

// Component to animate marker movement
const AnimatedMarker = ({ bus }) => {
  const markerRef = useRef(null);

  useEffect(() => {
    if (markerRef.current) {
      markerRef.current.setLatLng([bus.lat, bus.lon]);
    }
  }, [bus.lat, bus.lon]);

  return (
    <Marker
      ref={markerRef}
      position={[bus.lat, bus.lon]}
      icon={bus.status === "ghost" ? redIcon : greenIcon}
    >
      <Popup>
        Bus ID: {bus.id} <br />
        Status: {bus.status}
      </Popup>
    </Marker>
  );
};

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        const now = Math.floor(Date.now() / 1000);

        const updatedBuses = data.map(bus => ({
          ...bus,
          status: bus.timestamp && now - bus.timestamp > 120 ? "ghost" : "active" // 2 min
        }));

        setBuses(prevBuses => {
          // Merge previous bus positions for smooth animation
          const busMap = {};
          prevBuses.forEach(b => { busMap[b.id] = b; });
          return updatedBuses.map(b => ({
            ...b,
            lat: busMap[b.id]?.lat || b.lat,
            lon: busMap[b.id]?.lon || b.lon
          }));
        });

      } catch (error) {
        console.error("Error fetching bus data:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 5000); // fetch every 5 seconds
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      {/* Button container shifted top-left */}
      <div style={{ position: "absolute", top: 10, left: 10, zIndex: 1000, display: "flex", flexDirection: "column", gap: "10px" }}>
        <button
          onClick={() => setShowChart(!showChart)}
          style={{
            padding: "10px 20px",
            backgroundColor: "#007bff",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: "pointer"
          }}
        >
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      <MapContainer
        center={[40.7128, -74.006]}
        zoom={11}
        style={{ height: "100vh", width: "100%" }}
        scrollWheelZoom={true}
        zoomControl={false} // disable default zoom
      >
        <ZoomControl position="topleft" />  {/* Zoom buttons top-left */}
        <TileLayer
          url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
          attribution=""
        />

        {buses.map((bus, index) => (
          <AnimatedMarker key={`${bus.id}-${index}`} bus={bus} />
        ))}
      </MapContainer>

      {showChart && <BusTrendChart buses={buses || []} />}
    </div>
  );
};

export default MapComponent;
